import AppKit

/// The Mac Clean vacuum icon, embedded as base64 so it loads identically
/// under `swift run` (no .app bundle) and inside the shipped DMG
/// (no SwiftPM resource-bundle plumbing to break). Source: the Canva
/// design selected by the user, exported at 256px.
enum VacuumAsset {
    static let image: NSImage = {
        let b64 = ""
        guard let data = Data(base64Encoded: b64), let img = NSImage(data: data) else {
            // Fallback so the menu bar never goes blank.
            return NSImage(systemSymbolName: "wand.and.sparkles", accessibilityDescription: "Mac Clean")
                ?? NSImage()
        }
        return img
    }()
}
